 32→/// A concrete, physical action ready to do. Has a context (required) and
 33→/// an optional project link (projects come in Step 6, so project_id is
 34→/// nullable for now).
 35→///
 36→/// State machine:
 37→///   Active --complete()--> Completed
 38→///
 39→/// Completed actions are removed from the active Next Actions list.
 40→#[derive(Debug, Clone)]
 41→pub enum NextAction {
 42→    Active {
 43→        id: NextActionId,
 44→        user_id: UserId,
 45→        context_id: ContextId,
 46→        project_id: Option<ProjectId>,
 47→        title: TodoTitle,
 48→        created_at: DateTime<Utc>,
 49→    },
 50→    Completed {
 51→        id: NextActionId,
 52→        user_id: UserId,
 53→        context_id: ContextId,
 54→        project_id: Option<ProjectId>,
 55→        title: TodoTitle,
 56→        created_at: DateTime<Utc>,
 57→        completed_at: DateTime<Utc>,
 58→    },
 59→}
 60→
 61→impl NextAction {
 62→    pub fn new(user_id: UserId, context_id: ContextId, title: TodoTitle) -> Self {
 63→        Self::Active {
 64→            id: NextActionId::new(),
 65→            user_id,
 66→            context_id,
 67→            project_id: None,
 68→            title,
 69→            created_at: Utc::now(),
 70→        }
 71→    }
 72→
 73→    pub fn new_for_project(
 74→        user_id: UserId,
 75→        context_id: ContextId,
 76→        project_id: ProjectId,
 77→        title: TodoTitle,
 78→    ) -> Self {
 79→        Self::Active {
 80→            id: NextActionId::new(),
 81→            user_id,
 82→            context_id,
 83→            project_id: Some(project_id),
 84→            title,
 85→            created_at: Utc::now(),
 86→        }
 87→    }
 88→
 89→    pub fn from_parts(
 90→        id: NextActionId,
 91→        user_id: UserId,
 92→        context_id: ContextId,
 93→        project_id: Option<ProjectId>,
 94→        title: TodoTitle,
 95→        created_at: DateTime<Utc>,
 96→        completed_at: Option<DateTime<Utc>>,
 97→    ) -> Self {
 98→        match completed_at {
 99→            Some(completed_at) => Self::Completed {
100→                id,
101→                user_id,
102→                context_id,
103→                project_id,
104→                title,
105→                created_at,
106→                completed_at,
107→            },
108→            None => Self::Active {
109→                id,
110→                user_id,
111→                context_id,
112→                project_id,
113→                title,
114→                created_at,
115→            },
116→        }
117→    }
118→
119→    pub fn id(&self) -> &NextActionId {
120→        match self {
121→            Self::Active { id, .. } | Self::Completed { id, .. } => id,
122→        }
123→    }
124→
125→    pub fn user_id(&self) -> &UserId {
126→        match self {
127→            Self::Active { user_id, .. } | Self::Completed { user_id, .. } => user_id,
128→        }
129→    }
130→
131→    pub fn context_id(&self) -> &ContextId {
132→        match self {
133→            Self::Active { context_id, .. } | Self::Completed { context_id, .. } => context_id,
134→        }
135→    }
136→
137→    pub fn project_id(&self) -> Option<&ProjectId> {
138→        match self {
139→            Self::Active { project_id, .. } | Self::Completed { project_id, .. } => {
140→                project_id.as_ref()
141→            }
142→        }
143→    }
144→
145→    pub fn title(&self) -> &TodoTitle {
146→        match self {
147→            Self::Active { title, .. } | Self::Completed { title, .. } => title,
148→        }
149→    }
150→
151→    pub fn created_at(&self) -> &DateTime<Utc> {
152→        match self {
153→            Self::Active { created_at, .. } | Self::Completed { created_at, .. } => created_at,
154→        }
155→    }
156→
157→    pub fn is_active(&self) -> bool {
158→        matches!(self, Self::Active { .. })
159→    }
160→
161→    pub fn is_completed(&self) -> bool {
162→        matches!(self, Self::Completed { .. })
163→    }
164→
165→    /// Transitions an Active next action to Completed.
166→    /// If already completed, returns self unchanged.
167→    pub fn complete(self) -> Self {
168→        match self {
169→            Self::Active {
170→                id,
171→                user_id,
172→                context_id,
173→                project_id,
174→                title,
175→                created_at,
176→            } => Self::Completed {
177→                id,
178→                user_id,
179→                context_id,
180→                project_id,
181→                title,
182→                created_at,
183→                completed_at: Utc::now(),
184→            },
185→            completed @ Self::Completed { .. } => completed,
186→        }
187→    }
188→}
