use axum::http::HeaderMap;
use axum::response::{Html, IntoResponse, Response};

mod auth;
mod contexts;
mod dashboard;
mod forgot_password;
mod gtd_placeholders;
mod health_check;
mod inbox;
mod index;
mod login;
mod next_actions;
mod projects;
mod register;
mod todos;

fn is_htmx_request(headers: &HeaderMap) -> bool {
    headers.contains_key("hx-request")
}

fn htmx_response_with_announce(body: Html<String>, message: &str) -> Response {
    let trigger_json = format!(r#"{{"announce":"{}"}}"#, message);
    (
        [(
            axum::http::header::HeaderName::from_static("hx-trigger"),
            axum::http::HeaderValue::from_str(&trigger_json).unwrap(),
        )],
        body,
    )
        .into_response()
}

pub use contexts::{
    get_contexts, get_edit_context, post_context, post_delete_context, post_edit_context,
};
pub use dashboard::get_dashboard;
pub use forgot_password::get_forgot_password;
pub use gtd_placeholders::{get_review, get_someday_maybe, get_waiting_for};
pub use health_check::health_check;
pub use inbox::{get_inbox, post_clarify_inbox_item, post_delete_inbox_item, post_inbox};
pub use index::index;
pub use login::{get_login, post_login, post_logout};
pub use next_actions::{
    get_edit_next_action, get_next_action_item, get_next_actions, post_complete_next_action,
    post_delete_next_action, post_edit_next_action, post_next_action,
};
pub use projects::{
    get_edit_project, get_project_detail, get_project_item, get_projects, post_complete_project,
    post_delete_project, post_edit_project, post_project, post_project_next_action,
};
pub use register::{get_register, post_register};
pub use todos::{
    get_edit_todo, get_todo_item, get_todos_page, post_delete_todo, post_edit_todo, post_todo,
    post_toggle_todo,
};

use axum::Router;
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;
use tokio::net::TcpListener;
use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
use tower_http::services::ServeDir;
use tower_http::trace::TraceLayer;
use tower_sessions::SessionManagerLayer;
use tower_sessions_sqlx_store::PostgresStore;

use crate::configuration::Settings;
use crate::routes::{
    get_contexts, get_dashboard, get_edit_context, get_edit_next_action, get_edit_project,
    get_edit_todo, get_forgot_password, get_inbox, get_login, get_next_action_item,
    get_next_actions, get_project_detail, get_project_item, get_projects, get_register, get_review,
    get_someday_maybe, get_todo_item, get_todos_page, get_waiting_for, health_check, index,
    post_clarify_inbox_item, post_complete_next_action, post_complete_project, post_context,
    post_delete_context, post_delete_inbox_item, post_delete_next_action, post_delete_project,
    post_delete_todo, post_edit_context, post_edit_next_action, post_edit_project, post_edit_todo,
    post_inbox, post_login, post_logout, post_next_action, post_project, post_project_next_action,
    post_register, post_todo, post_toggle_todo,
};

pub struct Application {
    listener: TcpListener,
    pool: PgPool,
}

impl Application {
    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
        let pool = PgPoolOptions::new()
            .max_connections(5)
            .connect_with(settings.database.connect_options())
            .await?;

        sqlx::migrate!("./migrations").run(&pool).await?;

        let session_store = PostgresStore::new(pool.clone());
        session_store.migrate().await?;

        let address = format!(
            "{}:{}",
            settings.application.host, settings.application.port
        );
        let listener = TcpListener::bind(&address).await?;

        tracing::info!("Listening on {}", listener.local_addr()?);

        Ok(Self { listener, pool })
    }

    pub fn port(&self) -> u16 {
        self.listener.local_addr().unwrap().port()
    }

    pub fn router(pool: PgPool) -> Router {
        let x_request_id = axum::http::HeaderName::from_static("x-request-id");

        let session_store = PostgresStore::new(pool.clone());
        let session_layer = SessionManagerLayer::new(session_store);

        Router::new()
            .route("/", axum::routing::get(index))
            .route("/dashboard", axum::routing::get(get_dashboard))
            .route("/inbox", axum::routing::get(get_inbox).post(post_inbox))
            .route(
                "/inbox/{id}/delete",
                axum::routing::post(post_delete_inbox_item),
            )
            .route(
                "/inbox/{id}/clarify",
                axum::routing::post(post_clarify_inbox_item),
            )
            .route(
                "/contexts",
                axum::routing::get(get_contexts).post(post_context),
            )
            .route(
                "/contexts/{id}/edit",
                axum::routing::get(get_edit_context).post(post_edit_context),
            )
            .route(
                "/contexts/{id}/delete",
                axum::routing::post(post_delete_context),
            )
            .route(
                "/next-actions",
                axum::routing::get(get_next_actions).post(post_next_action),
            )
            .route(
                "/next-actions/{id}",
                axum::routing::get(get_next_action_item),
            )
            .route(
                "/next-actions/{id}/complete",
                axum::routing::post(post_complete_next_action),
            )
            .route(
                "/next-actions/{id}/delete",
                axum::routing::post(post_delete_next_action),
            )
            .route(
                "/next-actions/{id}/edit",
                axum::routing::get(get_edit_next_action).post(post_edit_next_action),
            )
            .route(
                "/projects",
                axum::routing::get(get_projects).post(post_project),
            )
            .route("/projects/{id}", axum::routing::get(get_project_detail))
            .route("/projects/{id}/item", axum::routing::get(get_project_item))
            .route(
                "/projects/{id}/complete",
                axum::routing::post(post_complete_project),
            )
            .route(
                "/projects/{id}/delete",
                axum::routing::post(post_delete_project),
            )
            .route(
                "/projects/{id}/edit",
                axum::routing::get(get_edit_project).post(post_edit_project),
            )
            .route(
                "/projects/{id}/next-actions",
                axum::routing::post(post_project_next_action),
            )
            .route("/waiting-for", axum::routing::get(get_waiting_for))
            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
            .route("/review", axum::routing::get(get_review))
            .route(
                "/register",
                axum::routing::get(get_register).post(post_register),
            )
            .route("/login", axum::routing::get(get_login).post(post_login))
            .route("/forgot-password", axum::routing::get(get_forgot_password))
            .route("/logout", axum::routing::post(post_logout))
            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
            .route("/todos/{id}", axum::routing::get(get_todo_item))
            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
            .route(
                "/todos/{id}/edit",
                axum::routing::get(get_edit_todo).post(post_edit_todo),
            )
            .route("/health_check", axum::routing::get(health_check))
            .nest_service("/static", ServeDir::new("static"))
            .layer(session_layer)
            .layer(TraceLayer::new_for_http())
            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
            .with_state(pool)
    }

    pub async fn run(self) -> Result<(), std::io::Error> {
        let router = Self::router(self.pool);
        axum::serve(self.listener, router).await
    }
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{Project, ProjectId, TodoTitle, UserId};

struct ProjectRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
    dropped_at: Option<DateTime<Utc>>,
}

impl ProjectRecord {
    fn into_domain(self) -> Project {
        let id = ProjectId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        Project::from_parts(
            id,
            user_id,
            title,
            self.created_at,
            self.completed_at,
            self.dropped_at,
        )
    }
}

pub async fn insert_project(
    executor: impl PgExecutor<'_>,
    project: &Project,
) -> Result<(), sqlx::Error> {
    let (completed_at, dropped_at): (Option<&DateTime<Utc>>, Option<&DateTime<Utc>>) = match project
    {
        Project::Completed { completed_at, .. } => (Some(completed_at), None),
        Project::Dropped { dropped_at, .. } => (None, Some(dropped_at)),
        Project::Active { .. } => (None, None),
    };

    sqlx::query!(
        r#"INSERT INTO projects (id, user_id, title, created_at, completed_at, dropped_at)
           VALUES ($1, $2, $3, $4 :: timestamptz, $5 :: timestamptz, $6 :: timestamptz)"#,
        project.id().as_uuid(),
        project.user_id().as_uuid(),
        project.title().as_str(),
        project.created_at() as &DateTime<Utc>,
        completed_at as Option<&DateTime<Utc>>,
        dropped_at as Option<&DateTime<Utc>>,
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_active_projects_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<Project>, sqlx::Error> {
    let records = sqlx::query_as!(
        ProjectRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>",
           dropped_at as "dropped_at: DateTime<Utc>"
           FROM projects
           WHERE user_id = $1 AND completed_at IS NULL AND dropped_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records.into_iter().map(|r| r.into_domain()).collect())
}

pub async fn find_project_by_id(
    executor: impl PgExecutor<'_>,
    project_id: &ProjectId,
) -> Result<Option<Project>, sqlx::Error> {
    let record: Option<ProjectRecord> = sqlx::query_as!(
        ProjectRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>",
           dropped_at as "dropped_at: DateTime<Utc>"
           FROM projects WHERE id = $1"#,
        project_id.as_uuid(),
    )
    .fetch_optional(executor)
    .await?;

    Ok(record.map(|r| r.into_domain()))
}

pub async fn complete_project(
    pool: &PgPool,
    project_id: &ProjectId,
    completed_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE projects SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as &DateTime<Utc>,
        project_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_project(pool: &PgPool, project_id: &ProjectId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM projects WHERE id = $1"#,
        project_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM projects WHERE user_id = $1 AND completed_at IS NULL AND dropped_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

/// Count stalled projects (active projects with no active next actions)
pub async fn count_stalled_projects(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!"
           FROM projects p
           WHERE p.user_id = $1
             AND p.completed_at IS NULL
             AND p.dropped_at IS NULL
             AND NOT EXISTS (
                 SELECT 1 FROM next_actions na
                 WHERE na.project_id = p.id
                   AND na.completed_at IS NULL
             )"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn update_project_title(
    pool: &PgPool,
    project_id: &ProjectId,
    title: &TodoTitle,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE projects SET title = $1 WHERE id = $2"#,
        title.as_str(),
        project_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

/// Count active next actions for a specific project
pub async fn count_project_next_actions(
    pool: &PgPool,
    project_id: &ProjectId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM next_actions WHERE project_id = $1 AND completed_at IS NULL"#,
        project_id.as_uuid(),
    )
